import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"OpenHands — References & Resources","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/openhands/references.md","filePath":"research/agents/openhands/references.md"}'),r={name:"research/agents/openhands/references.md"};function d(s,e,i,c,l,h){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="openhands-—-references-resources" tabindex="-1">OpenHands — References &amp; Resources <a class="header-anchor" href="#openhands-—-references-resources" aria-label="Permalink to &quot;OpenHands — References &amp; Resources&quot;">​</a></h1><blockquote><p>Comprehensive link collection for the OpenHands (formerly OpenDevin) AI software engineering agent. Organized by category for quick lookup.</p></blockquote><hr><h2 id="primary-sources" tabindex="-1">Primary Sources <a class="header-anchor" href="#primary-sources" aria-label="Permalink to &quot;Primary Sources&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Resource</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td>GitHub Repository</td><td><a href="https://github.com/All-Hands-AI/OpenHands" target="_blank" rel="noreferrer">https://github.com/All-Hands-AI/OpenHands</a></td><td>Main source code (MIT license)</td></tr><tr><td>Documentation</td><td><a href="https://docs.all-hands.dev" target="_blank" rel="noreferrer">https://docs.all-hands.dev</a></td><td>Official docs site (redirects to docs.openhands.dev)</td></tr><tr><td>SDK Documentation</td><td><a href="https://docs.openhands.dev/sdk" target="_blank" rel="noreferrer">https://docs.openhands.dev/sdk</a></td><td>Software Agent SDK reference</td></tr><tr><td>Cloud Platform</td><td><a href="https://app.all-hands.dev" target="_blank" rel="noreferrer">https://app.all-hands.dev</a></td><td>Hosted SaaS offering</td></tr><tr><td>Website</td><td><a href="https://openhands.dev" target="_blank" rel="noreferrer">https://openhands.dev</a></td><td>Marketing / landing page</td></tr></tbody></table><hr><h2 id="related-repositories" tabindex="-1">Related Repositories <a class="header-anchor" href="#related-repositories" aria-label="Permalink to &quot;Related Repositories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Repository</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td>Software Agent SDK (V1)</td><td><a href="https://github.com/OpenHands/software-agent-sdk" target="_blank" rel="noreferrer">https://github.com/OpenHands/software-agent-sdk</a></td><td>Standalone SDK for building agents on the OpenHands runtime</td></tr><tr><td>OpenHands CLI</td><td><a href="https://github.com/OpenHands/OpenHands-CLI" target="_blank" rel="noreferrer">https://github.com/OpenHands/OpenHands-CLI</a></td><td>Command-line interface package (<code>openhands-cli</code>)</td></tr><tr><td>Benchmarks</td><td><a href="https://github.com/OpenHands/benchmarks" target="_blank" rel="noreferrer">https://github.com/OpenHands/benchmarks</a></td><td>Evaluation harnesses (SWE-bench, HumanEval, etc.)</td></tr><tr><td>Chrome Extension</td><td><a href="https://github.com/OpenHands/openhands-chrome-extension" target="_blank" rel="noreferrer">https://github.com/OpenHands/openhands-chrome-extension</a></td><td>Browser extension for triggering agents from GitHub issues</td></tr><tr><td>Theory-of-Mind (ToM-SWE)</td><td><a href="https://github.com/OpenHands/ToM-SWE" target="_blank" rel="noreferrer">https://github.com/OpenHands/ToM-SWE</a></td><td>Research module for theory-of-mind in SWE tasks</td></tr><tr><td>Documentation Site</td><td><a href="https://github.com/OpenHands/docs" target="_blank" rel="noreferrer">https://github.com/OpenHands/docs</a></td><td>Source for <a href="https://docs.openhands.dev" target="_blank" rel="noreferrer">https://docs.openhands.dev</a></td></tr></tbody></table><hr><h2 id="academic-papers" tabindex="-1">Academic Papers <a class="header-anchor" href="#academic-papers" aria-label="Permalink to &quot;Academic Papers&quot;">​</a></h2><h3 id="codeact-—-executable-code-actions-for-llm-agents" tabindex="-1">CodeAct — Executable Code Actions for LLM Agents <a class="header-anchor" href="#codeact-—-executable-code-actions-for-llm-agents" aria-label="Permalink to &quot;CodeAct — Executable Code Actions for LLM Agents&quot;">​</a></h3><ul><li><strong>Authors:</strong> Xingyao Wang, Yangyi Chen, Lifan Yuan, Yizhe Zhang, Yunzhu Li, Hao Peng, Heng Ji</li><li><strong>Link:</strong> <a href="https://arxiv.org/abs/2402.01030" target="_blank" rel="noreferrer">https://arxiv.org/abs/2402.01030</a></li><li><strong>Summary:</strong> Introduces the CodeAct paradigm — consolidating LLM tool use into executable Python code actions instead of rigid JSON schemas. Foundation of the <code>CodeActAgent</code>.</li></ul><h3 id="openhands-technical-report" tabindex="-1">OpenHands Technical Report <a class="header-anchor" href="#openhands-technical-report" aria-label="Permalink to &quot;OpenHands Technical Report&quot;">​</a></h3><ul><li><strong>Link:</strong> <a href="https://arxiv.org/abs/2511.03690" target="_blank" rel="noreferrer">https://arxiv.org/abs/2511.03690</a></li><li><strong>Summary:</strong> System-level description of the OpenHands platform covering architecture, sandboxed runtime, event stream, memory management, and benchmark results.</li></ul><h3 id="citation-file" tabindex="-1">Citation File <a class="header-anchor" href="#citation-file" aria-label="Permalink to &quot;Citation File&quot;">​</a></h3><ul><li><code>CITATION.cff</code> is available in the repository root for BibTeX / CFF-based citation tooling.</li></ul><hr><h2 id="documentation-links" tabindex="-1">Documentation Links <a class="header-anchor" href="#documentation-links" aria-label="Permalink to &quot;Documentation Links&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>URL</th><th>Notes</th></tr></thead><tbody><tr><td>Runtime Architecture</td><td><a href="https://docs.all-hands.dev/openhands/usage/architecture/runtime" target="_blank" rel="noreferrer">https://docs.all-hands.dev/openhands/usage/architecture/runtime</a></td><td>Docker sandbox, action-execution server, event flow</td></tr><tr><td>CLI Mode</td><td><a href="https://docs.openhands.dev/openhands/usage/run-openhands/cli-mode" target="_blank" rel="noreferrer">https://docs.openhands.dev/openhands/usage/run-openhands/cli-mode</a></td><td>Running OpenHands from the terminal</td></tr><tr><td>Local Setup</td><td><a href="https://docs.openhands.dev/openhands/usage/run-openhands/local-setup" target="_blank" rel="noreferrer">https://docs.openhands.dev/openhands/usage/run-openhands/local-setup</a></td><td>Development environment setup guide</td></tr><tr><td>Enterprise</td><td><a href="https://openhands.dev/enterprise" target="_blank" rel="noreferrer">https://openhands.dev/enterprise</a></td><td>Enterprise deployment &amp; licensing information</td></tr><tr><td>Microagents</td><td><a href="https://docs.openhands.dev/openhands/usage/architecture/microagents" target="_blank" rel="noreferrer">https://docs.openhands.dev/openhands/usage/architecture/microagents</a></td><td>Repo-level and knowledge micro-agents</td></tr><tr><td>Configuration</td><td><a href="https://docs.openhands.dev/openhands/usage/configuration" target="_blank" rel="noreferrer">https://docs.openhands.dev/openhands/usage/configuration</a></td><td>TOML config reference</td></tr></tbody></table><hr><h2 id="community-social" tabindex="-1">Community &amp; Social <a class="header-anchor" href="#community-social" aria-label="Permalink to &quot;Community &amp; Social&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Channel</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td>Slack Workspace</td><td><a href="https://openhands.dev/joinslack" target="_blank" rel="noreferrer">https://openhands.dev/joinslack</a> (short: <a href="https://dub.sh/openhands" target="_blank" rel="noreferrer">https://dub.sh/openhands</a>)</td><td>Primary community chat</td></tr><tr><td>Product Roadmap</td><td><a href="https://github.com/orgs/openhands/projects/1" target="_blank" rel="noreferrer">https://github.com/orgs/openhands/projects/1</a></td><td>GitHub Projects board tracking features &amp; milestones</td></tr><tr><td>Community Guide</td><td><code>COMMUNITY.md</code> in repo root</td><td>Contribution guidelines, governance, code of conduct</td></tr><tr><td>Discord / X</td><td>Linked from <a href="https://openhands.dev" target="_blank" rel="noreferrer">https://openhands.dev</a></td><td>Secondary social channels</td></tr></tbody></table><hr><h2 id="benchmark-results" tabindex="-1">Benchmark Results <a class="header-anchor" href="#benchmark-results" aria-label="Permalink to &quot;Benchmark Results&quot;">​</a></h2><h3 id="swe-bench" tabindex="-1">SWE-bench <a class="header-anchor" href="#swe-bench" aria-label="Permalink to &quot;SWE-bench&quot;">​</a></h3><ul><li><strong>Results Spreadsheet:</strong><a href="https://docs.google.com/spreadsheets/d/1wOUdFCMyY6Nt0AIqF705KN4JKOWgeI4wUGUP60krXXs" target="_blank" rel="noreferrer">https://docs.google.com/spreadsheets/d/1wOUdFCMyY6Nt0AIqF705KN4JKOWgeI4wUGUP60krXXs</a></li><li>OpenHands regularly publishes verified SWE-bench Lite and Full scores. Competitive with top proprietary agents.</li></ul><h3 id="terminal-bench-2-0" tabindex="-1">Terminal-Bench 2.0 <a class="header-anchor" href="#terminal-bench-2-0" aria-label="Permalink to &quot;Terminal-Bench 2.0&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Rank</th><th>Model</th><th>Score</th></tr></thead><tbody><tr><td>#49</td><td>Claude Opus 4.5</td><td>51.9 %</td></tr><tr><td>#58</td><td>GPT-5</td><td>43.8 %</td></tr></tbody></table><blockquote><p>Terminal-Bench evaluates autonomous terminal task completion. Ranks above reflect the OpenHands agent paired with the listed backbone model.</p></blockquote><hr><h2 id="key-source-code-files" tabindex="-1">Key Source Code Files <a class="header-anchor" href="#key-source-code-files" aria-label="Permalink to &quot;Key Source Code Files&quot;">​</a></h2><p>Useful starting points for architecture analysis of the <code>All-Hands-AI/OpenHands</code> repository.</p><h3 id="event-system" tabindex="-1">Event System <a class="header-anchor" href="#event-system" aria-label="Permalink to &quot;Event System&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>openhands/events/stream.py</code></td><td>Central event bus — append, subscribe, filter</td></tr><tr><td><code>openhands/events/event.py</code></td><td>Base <code>Event</code> dataclass (id, timestamp, source, cause)</td></tr></tbody></table><h3 id="actions-openhands-events-action" tabindex="-1">Actions (<code>openhands/events/action/</code>) <a class="header-anchor" href="#actions-openhands-events-action" aria-label="Permalink to &quot;Actions (\`openhands/events/action/\`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>commands.py</code></td><td><code>CmdRunAction</code>, <code>IPythonRunCellAction</code></td></tr><tr><td><code>files.py</code></td><td><code>FileReadAction</code>, <code>FileWriteAction</code>, <code>FileEditAction</code></td></tr><tr><td><code>agent.py</code></td><td><code>AgentFinishAction</code>, <code>AgentDelegateAction</code>, <code>AgentThinkAction</code></td></tr><tr><td><code>browse.py</code></td><td><code>BrowseURLAction</code>, <code>BrowseInteractiveAction</code></td></tr><tr><td><code>mcp.py</code></td><td>MCP (Model Context Protocol) tool-call actions</td></tr></tbody></table><h3 id="observations-openhands-events-observation" tabindex="-1">Observations (<code>openhands/events/observation/</code>) <a class="header-anchor" href="#observations-openhands-events-observation" aria-label="Permalink to &quot;Observations (\`openhands/events/observation/\`)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>commands.py</code></td><td><code>CmdOutputObservation</code> — shell command results</td></tr><tr><td><code>files.py</code></td><td><code>FileReadObservation</code>, <code>FileWriteObservation</code>, <code>FileEditObservation</code></td></tr><tr><td><code>browse.py</code></td><td><code>BrowserOutputObservation</code> — browser state snapshots</td></tr><tr><td><code>error.py</code></td><td><code>ErrorObservation</code> — runtime / agent errors</td></tr><tr><td><code>mcp.py</code></td><td>MCP tool-call responses</td></tr></tbody></table><h3 id="agent-controller" tabindex="-1">Agent &amp; Controller <a class="header-anchor" href="#agent-controller" aria-label="Permalink to &quot;Agent &amp; Controller&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>openhands/controller/agent_controller.py</code></td><td>Main control loop — step, budget, delegate, stuck detection</td></tr><tr><td><code>openhands/controller/agent.py</code></td><td>Abstract <code>Agent</code> base class</td></tr><tr><td><code>openhands/controller/stuck.py</code></td><td><code>StuckDetector</code> — identifies and breaks infinite loops</td></tr><tr><td><code>openhands/agenthub/codeact_agent/codeact_agent.py</code></td><td>Default <code>CodeActAgent</code> implementation</td></tr><tr><td><code>openhands/agenthub/codeact_agent/function_calling.py</code></td><td>Maps actions ↔ LLM function-call schemas</td></tr></tbody></table><h3 id="runtime" tabindex="-1">Runtime <a class="header-anchor" href="#runtime" aria-label="Permalink to &quot;Runtime&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>openhands/runtime/base.py</code></td><td>Abstract <code>Runtime</code> — execute actions, manage sandbox</td></tr><tr><td><code>openhands/runtime/action_execution_server.py</code></td><td>FastAPI server running <em>inside</em> the Docker sandbox</td></tr></tbody></table><h3 id="memory-context-management" tabindex="-1">Memory &amp; Context Management <a class="header-anchor" href="#memory-context-management" aria-label="Permalink to &quot;Memory &amp; Context Management&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>openhands/memory/memory.py</code></td><td>High-level memory orchestrator</td></tr><tr><td><code>openhands/memory/conversation_memory.py</code></td><td>Builds LLM message lists from event history</td></tr><tr><td><code>openhands/memory/condenser/condenser.py</code></td><td>Base condenser interface for context compression</td></tr><tr><td><code>openhands/memory/condenser/impl/</code></td><td>Concrete strategies: <code>LLMSummarizingCondenser</code>, <code>RecentEventsCondenser</code>, <code>AmortizedForgettingCondenser</code>, etc.</td></tr></tbody></table><h3 id="microagents" tabindex="-1">Microagents <a class="header-anchor" href="#microagents" aria-label="Permalink to &quot;Microagents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>openhands/microagent/microagent.py</code></td><td>Loads repo-level <code>.openhands/microagents/*.md</code> prompt snippets</td></tr></tbody></table><hr><h2 id="configuration-files" tabindex="-1">Configuration Files <a class="header-anchor" href="#configuration-files" aria-label="Permalink to &quot;Configuration Files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>config.template.toml</code></td><td>Annotated configuration template (LLM, agent, sandbox settings)</td></tr><tr><td><code>docker-compose.yml</code></td><td>Multi-container setup for local development</td></tr><tr><td><code>pyproject.toml</code></td><td>Python project metadata, dependencies, entry points</td></tr><tr><td><code>.openhands/microagents/</code></td><td>Directory for repo-specific microagent prompts</td></tr></tbody></table><hr><h2 id="version-licensing" tabindex="-1">Version &amp; Licensing <a class="header-anchor" href="#version-licensing" aria-label="Permalink to &quot;Version &amp; Licensing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Item</th><th>Detail</th></tr></thead><tbody><tr><td>Current Version</td><td><strong>v1.0.0+</strong> (V1 SDK migration in progress)</td></tr><tr><td>Legacy V0 Deprecation</td><td>V0 code paths marked for removal <strong>April 1, 2026</strong></td></tr><tr><td>Core License</td><td>MIT (<code>LICENSE</code> in repo root)</td></tr><tr><td>Enterprise License</td><td>Separate license under <code>enterprise/</code> directory</td></tr><tr><td>Python Requirement</td><td>≥ 3.12</td></tr><tr><td>Container Runtime</td><td>Docker (required for sandboxed execution)</td></tr></tbody></table><hr><h2 id="quick-start-commands" tabindex="-1">Quick-Start Commands <a class="header-anchor" href="#quick-start-commands" aria-label="Permalink to &quot;Quick-Start Commands&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install via pip</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">pip</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> openhands-ai</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run in headless / CLI mode</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">openhands</span><span style="color:#A6E3A1;"> --mode</span><span style="color:#A6E3A1;"> cli</span><span style="color:#A6E3A1;"> --model</span><span style="color:#A6E3A1;"> anthropic/claude-sonnet-4-20250514</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Run via Docker (recommended)</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">docker</span><span style="color:#A6E3A1;"> run</span><span style="color:#A6E3A1;"> -it</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  -e</span><span style="color:#A6E3A1;"> LLM_API_KEY=</span><span style="color:#CDD6F4;">$OPENAI_API_KEY </span><span style="color:#F5C2E7;">\\</span></span>
<span class="line"><span style="color:#A6E3A1;">  -p</span><span style="color:#A6E3A1;"> 3000:3000</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  ghcr.io/all-hands-ai/openhands:latest</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Development setup</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">git</span><span style="color:#A6E3A1;"> clone</span><span style="color:#A6E3A1;"> https://github.com/All-Hands-AI/OpenHands.git</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">cd</span><span style="color:#A6E3A1;"> OpenHands</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">make</span><span style="color:#A6E3A1;"> build</span><span style="color:#6C7086;font-style:italic;">        # builds Docker sandbox image</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">make</span><span style="color:#A6E3A1;"> run</span><span style="color:#6C7086;font-style:italic;">          # starts the full stack</span></span></code></pre></div><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./overview.html">overview.md</a> — Architecture deep-dive and design analysis</li><li><a href="./key-innovations.html">key-innovations.md</a> — What makes OpenHands unique</li><li><a href="./../comparison.html">comparison.md</a> — Side-by-side with other AI coding agents</li></ul><hr><p><em>Last updated: 2025-07-17</em></p>`,60)])])}const u=t(r,[["render",d]]);export{m as __pageData,u as default};
